text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "decisions": {
      "confirmed": [
        "공개 릴리스 목표는 스모크 테스트 통과를 전제로 금요일 15:00 KST로 설정한다.",
        "packageName 불일치가 발생하면 먼저 패키지 설정(계약)을 점검하고, 계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 검토로 진행한다."
      ],
      "rejected_proposals": [
        "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경하자는 제안은 기각되었다."
      ],
      "internal_stretch_goals": [
        "수요일 릴리스는 내부 스트레치 목표이며, 확정 공개 일정이 아니다."
      ]
    },
    "non_decisions": [
      "README 설치 단계는 목요일까지 가능하면 검토하자는 의견이 있었으나 담당자가 지정되지 않았다.",
      "Hara의 tarball 경로 확인은 Minjun의 스모크 결과 공유 이후 수행하기로 했으나 정확한 마감 시각은 정하지 않았다."
    ],
    "risks": [
      "tarball 경로 오류 시 릴리스 지연 가능성",
      "README 설치 단계가 최신이 아니면 릴리스 노트가 사용자에게 오해를 줄 가능성"
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 명시할 것인가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로 점검",
      "due": "미정",
      "status": "확정(조건부 트리거)",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 단계 검토(가능하면 목요일)",
      "due": "목요일(가능하면)",
      "status": "미확정(담당자 미지정)",
      "source_certainty": "suggested_not_assigned"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 이후 Minjun의 스모크 테스트 결과 수신 여부",
      "결과에 따라 tarball 경로 점검 수행 및 결과 기록",
      "금요일 12:00 KST까지 Doyun의 트리아지 노트 작성 완료 여부",
      "README 설치 단계 검토 담당자 지정 필요 여부",
      "최종 릴리스 승인 권한자 확정",
      "릴리스 노트에 수요일 내부 스트레치 목표 언급 여부 결정"
    ],
    "what_not_to_invent": [
      "고객명/외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "미지정 담당자/미합의 마감시각"
    ]
  },
  "non_invention_rules": [
    "회의 원문에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "명시되지 않은 담당자(owner)와 데드라인을 임의 확정하지 않는다.",
    "확정 결정과 제안/미결 사안을 분리해 기록한다.",
    "조건부 합의(예: 스모크 통과 시)를 절대적 확정처럼 표현하지 않는다."
  ]
}
